mapper.sql:
SELECT MST.FAM_SEQ , MEM.SVC_CNTR_NO , SUB.SUB_LINK_NAME , SUBSTR(CRYPTO_AES256.DEC_AES(CUS.CUSTOMER_SSN), 1, 6) AS BIRTH_DT , FN_GET_AGE_NEW(CRYPTO_AES256.DEC_AES(CUS.CUSTOMER_SSN)) AS AGE , SUB.SUBSCRIBER_NO , MST.USE_YN AS USE_YN , FN_GET_CODENM('RCP9045', MST.USE_YN) AS USE_YN_NM , MST.STRT_DTTM , MST.END_DTTM , MST.END_CODE , FN_GET_CODENM('RCP9049', MST.END_CODE) AS END_CODE_NM , MST.END_MSG , NVL(FN_GET_USRNM(MST.REGST_ID), MST.REGST_ID) AS REGST_ID , TO_CHAR(MST.REGST_DTTM, 'YYYYMMDDHH24MISS') AS REGST_DTTM , NVL(FN_GET_USRNM(MST.RVISN_ID), MST.RVISN_ID) AS RVISN_ID , TO_CHAR(MST.RVISN_DTTM, 'YYYYMMDDHH24MISS') AS RVISN_DTTM FROM MSP_FAM_REL_MST MST , ( SELECT FAM_SEQ , SVC_CNTR_NO , RANK() OVER (PARTITION BY FAM_SEQ ORDER BY USE_YN DESC, SEQ) RNK FROM MSP_FAM_REL_MEM WHERE MEM_TYPE = '10' ) MEM , MSP_JUO_SUB_INFO SUB , MSP_JUO_CUS_INFO CUS WHERE MST.FAM_SEQ = MEM.FAM_SEQ AND MEM.RNK = 1 AND MEM.SVC_CNTR_NO = SUB.SVC_CNTR_NO AND SUB.CUSTOMER_ID = CUS.CUSTOMER_ID
AND SUBSTR(MST.STRT_DTTM, 1, 8) BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND EXISTS ( SELECT 1 FROM MSP_FAM_REL_MEM MEM2 WHERE MEM2.FAM_SEQ = MST.FAM_SEQ AND MEM2.SVC_CNTR_NO = #{searchName} )
AND EXISTS ( SELECT 1 FROM MSP_FAM_REL_MEM MEM2 , MSP_JUO_SUB_INFO SUB2 WHERE MEM2.FAM_SEQ = MST.FAM_SEQ AND MEM2.SVC_CNTR_NO = SUB2.SVC_CNTR_NO AND SUB2.SUBSCRIBER_NO = #{searchName} )
AND MST.USE_YN = #{useYn}
ORDER BY MST.FAM_SEQ DESC

mapper.select:
/* FamilyMgmtMapper.countFamilyMemberParent */
SELECT COUNT(*)
  FROM MSP_FAM_REL_MEM
 WHERE FAM_SEQ = #{famSeq}
   AND MEM_TYPE = '10'
   AND USE_YN = 'Y'

/* FamilyMgmtMapper.countFamilyMemberChild */
SELECT COUNT(*)
  FROM MSP_FAM_REL_MEM
 WHERE FAM_SEQ = #{famSeq}
   AND MEM_TYPE = '20'
   AND USE_YN = 'Y'

mapper.insert:
/* FamilyMgmtMapper.insertFamilyRel */

	SELECT SQ_FAM_REL_MST.NEXTVAL AS famSeq FROM DUAL

INSERT INTO MSP_FAM_REL_MST (
	FAM_SEQ
	, USE_YN
	, STRT_DTTM
	, END_DTTM
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{famSeq}
	, 'Y'
	, #{strtDttm}
	, '99991231235959'
	, #{sessionUserId}
    , SYSDATE
	, #{sessionUserId}
	, SYSDATE
)

/* FamilyMgmtMapper.insertFamilyParent */

	SELECT NVL(MAX(SEQ), 0) + 1 AS seq FROM MSP_FAM_REL_MEM WHERE FAM_SEQ = #{famSeq}

INSERT INTO MSP_FAM_REL_MEM (
	FAM_SEQ
	, SEQ
	, SVC_CNTR_NO
	, CONTRACT_NUM
	, MEM_TYPE
	, USE_YN
	, STRT_DTTM
	, END_DTTM
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{famSeq}
	, #{seq}
	, #{svcCntrNo}
    , ( SELECT CONTRACT_NUM
    	  FROM MSP_JUO_SUB_INFO
    	 WHERE SVC_CNTR_NO = #{svcCntrNo}
    	   AND ROWNUM = 1 )
	, '10'
    , 'Y'
    , #{strtDttm}
    , '99991231235959'
	, #{sessionUserId}
	, SYSDATE
	, #{sessionUserId}
	, SYSDATE
)

/* FamilyMgmtMapper.insertFamilyChild */

	SELECT NVL(MAX(SEQ), 0) + 1 AS seq FROM MSP_FAM_REL_MEM WHERE FAM_SEQ = #{famSeq}

INSERT INTO MSP_FAM_REL_MEM (
	FAM_SEQ
	, SEQ
	, SVC_CNTR_NO
	, CONTRACT_NUM
	, MEM_TYPE
	, CHILD_TYPE
	, USE_YN
	, STRT_DTTM
	, END_DTTM
	, REGST_ID
	, REGST_DTTM
	, RVISN_ID
	, RVISN_DTTM
) VALUES (
	#{famSeq}
	, #{seq}
	, #{svcCntrNo}
	, ( SELECT CONTRACT_NUM
		  FROM MSP_JUO_SUB_INFO
		 WHERE SVC_CNTR_NO = #{svcCntrNo}
		   AND ROWNUM = 1 )
	, '20'
	, #{childType}
	, 'Y'
	, #{strtDttm}


			, #{endDttm}


			, '99991231235959'


	, #{sessionUserId}
	, SYSDATE
	, #{sessionUserId}
	, SYSDATE
)

mapper.update:
/* FamilyMgmtMapper.cancelFamilyRel */
UPDATE MSP_FAM_REL_MST
   SET END_DTTM = #{endDttm}
       , END_CODE = #{endCode}
	   , END_MSG = #{endMsg}
	   , USE_YN = 'N'
	   , RVISN_ID = #{sessionUserId}
	   , RVISN_DTTM = SYSDATE
 WHERE FAM_SEQ = #{famSeq}
   AND USE_YN = 'Y'

/* FamilyMgmtMapper.cancelFamilyAllMember */
UPDATE MSP_FAM_REL_MEM
   SET END_DTTM = #{endDttm}
	   , END_CODE = #{endCode}
	   , END_MSG = #{endMsg}
	   , USE_YN = 'N'
	   , RVISN_ID = #{sessionUserId}
	   , RVISN_DTTM = SYSDATE
 WHERE FAM_SEQ = #{famSeq}
   AND USE_YN = 'Y'

/* FamilyMgmtMapper.cancelFamilyMember */
UPDATE MSP_FAM_REL_MEM
   SET END_DTTM = #{endDttm}
	   , END_CODE = #{endCode}
	   , END_MSG = #{endMsg}
	   , USE_YN = 'N'
	   , RVISN_ID = #{sessionUserId}
	   , RVISN_DTTM = SYSDATE
 WHERE FAM_SEQ = #{famSeq}
   AND SEQ = #{seq}
   AND USE_YN = 'Y'
